/**
 * Patch-regression guards.
 *
 * The TypeScript client is regenerated by regenerate_ts.py, which applies two
 * codegen bug-fix patches after openapi-generator runs:
 *
 *   1. patch_optional_extends   — allOf child interfaces wrongly mark inherited
 *      required properties as optional (`type?`); the patch removes the `?`.
 *   2. patch_missing_token_request — AuthenticationApi imports a `TokenRequest`
 *      model that openapi-generator never generates; the patch strips it.
 *
 * These tests fail if a future regeneration drops either patch, or if the
 * upstream generator changes in a way that reintroduces the bug. They assert
 * against the generated source text and the compiled type shape, since the
 * bugs are structural (interface declarations / dangling imports) rather than
 * runtime behavior.
 */
import { readFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";
import { describe, expect, it } from "vitest";

import type { DfdDiagram } from "../src/models/DfdDiagram";
import type { Edge } from "../src/models/Edge";
import type { Node } from "../src/models/Node";

const here = dirname(fileURLToPath(import.meta.url));
const srcDir = resolve(here, "..", "src");

function readModel(name: string): string {
  return readFileSync(resolve(srcDir, "models", `${name}.ts`), "utf-8");
}

describe("patch_optional_extends: inherited required props stay required", () => {
  // The patch targets these (child, property) pairs. Each must be declared
  // WITHOUT a trailing `?` in the generated interface.
  const cases: Array<[model: string, prop: string]> = [
    ["DfdDiagram", "type"],
    ["DfdDiagramInput", "type"],
    ["Edge", "shape"],
    ["Node", "shape"],
  ];

  it.each(cases)("%s.%s is declared as required", (model, prop) => {
    const source = readModel(model);
    // Optional form `prop?:` must not appear; required form `prop:` must.
    expect(source, `${model}.${prop} regressed to optional`).not.toMatch(
      new RegExp(`\\b${prop}\\?:`),
    );
    expect(source).toMatch(new RegExp(`\\b${prop}:`));
  });

  it("enforces required props at the type level", () => {
    // Type-level guard: a DfdDiagram literal missing `type`/`cells`, or an
    // Edge/Node missing `shape`, must be a compile error. @ts-expect-error
    // fails the build (and thus the test run) if the property became optional.

    // @ts-expect-error - `type` and `cells` are required on DfdDiagram
    const badDiagram: DfdDiagram = { id: "d", name: "n" } as DfdDiagram;
    expect(badDiagram).toBeDefined();

    // @ts-expect-error - `shape` is required on Edge
    const badEdge: Edge = {} as Edge;
    expect(badEdge).toBeDefined();

    // @ts-expect-error - `shape` is required on Node
    const badNode: Node = {} as Node;
    expect(badNode).toBeDefined();
  });
});

describe("patch_missing_token_request: no dangling TokenRequest reference", () => {
  const authApi = readFileSync(
    resolve(srcDir, "apis", "AuthenticationApi.ts"),
    "utf-8",
  );

  it("does not reference the un-generated TokenRequest model", () => {
    // Word-boundary match so the legitimate IntrospectTokenRequest /
    // RefreshTokenRequest / RevokeTokenRequest param interfaces don't trip it.
    expect(authApi).not.toMatch(/\bTokenRequest\b/);
    expect(authApi).not.toMatch(/\bTokenRequestToJSON\b/);
    expect(authApi).not.toMatch(/\bTokenRequestFromJSON\b/);
  });
});
